def bubble_sort(arr):
    n = len(arr)
    for i in range(n - 1):
        swapped = False
        for j in range(n - 1 - i):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swapped = True
        print(f"{i+1}회전 후: {arr}")
        if not swapped:   # 한 번도 교환이 없었다면 이미 정렬 완료
            break
    return arr

bubble_sort([5, 2, 8, 1, 4])

def selection_sort(arr):
    n = len(arr)
    for i in range(n - 1):
        min_idx = i
        for j in range(i + 1, n):
            if arr[j] < arr[min_idx]:
                min_idx = j
        arr[i], arr[min_idx] = arr[min_idx], arr[i]
        print(f"{i+1}단계 후: {arr}")
    return arr

selection_sort([5, 2, 8, 1, 4])
